TEMPLATE = """# Check: {name}
# Category: {category}
# Severity: {severity}
# ID: {check_id}
# Requirements: None
# ============================================

# LDAP search (ADSI / DirectorySearcher)
$searcher = [ADSISearcher]'{filter}'
$searcher.PageSize = 1000
$searcher.PropertiesToLoad.Clear()
@({props}) | ForEach-Object {{ [void]$searcher.PropertiesToLoad.Add($_) }}

$results = $searcher.FindAll()
$results | ForEach-Object {{
  $p = $_.Properties
  [PSCustomObject]@{{
    Label = '{label}'
    Name = $p['name'][0]
    DistinguishedName = $p['distinguishedname'][0]
  }}
}}
"""

if __name__ == '__main__':
    suite_root = sys.argv[1] if len(sys.argv) > 1 else '.'
    rebuilt = 0
    for check_id, d in CHECKS.items():
        content = TEMPLATE.format(
            name=d['name'], category=d['cat'].replace('_', ' '),
            severity=d['severity'], check_id=check_id,
            filter=d['filter'], props=d['props'],
            label=d['label']
        )
        # Find the check dir
        for root, dirs, files in os.walk(suite_root):
            if 'adsi.ps1' in files:
                # Check if this is the right check
                adsi_path = os.path.join(root, 'adsi.ps1')
                with open(adsi_path) as f:
                    txt = f.read()
                if f'# ID: {check_id}' in txt:
                    with open(adsi_path, 'w') as f:
                        f.write(content)
                    rebuilt += 1
                    print(f"Rebuilt: {check_id}")
                    break
    print(f"Total rebuilt: {rebuilt}")
